exercises.solution_code:
#include <iostream>
#include <string>

std::string classifyTemp(int temp) {
    return (temp < 0) ? "freezing"
         : (temp < 15) ? "cold"
         : "warm";
}

int main() {
    int t{};
    std::cin >> t;
    std::cout << t << " degrees: " << classifyTemp(t) << "\n";
    return 0;
}

