#include <iomanip>
#include <iostream>

int main() {
    std::cout << std::left << std::setw(8) << "A"
              << std::setw(8) << "B"
              << "|A-B|" << '\n';

    int a1{}, b1{};
    std::cin >> a1 >> b1;
    int diff1 = a1 - b1;
    int abs1 = (diff1 >= 0) ? diff1 : -diff1;
    std::cout << std::left << std::setw(8) << a1
              << std::setw(8) << b1
              << abs1 << '\n';

    int a2{}, b2{};
    std::cin >> a2 >> b2;
    int diff2 = a2 - b2;
    int abs2 = (diff2 >= 0) ? diff2 : -diff2;
    std::cout << std::left << std::setw(8) << a2
              << std::setw(8) << b2
              << abs2 << '\n';

    int a3{}, b3{};
    std::cin >> a3 >> b3;
    int diff3 = a3 - b3;
    int abs3 = (diff3 >= 0) ? diff3 : -diff3;
    std::cout << std::left << std::setw(8) << a3
              << std::setw(8) << b3
              << abs3 << '\n';

    return 0;
}
